package ir.tahamohamadi.resume; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.util.UUID;
@Entity @Table(name="resume_entry_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class ResumeEntryTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="resume_entry_id",nullable=false) private ResumeEntry entry; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false) private String title; @Column(nullable=false) private String organization; private String location; @Column(columnDefinition="text") private String summary; private ResumeEntryTranslation(UUID id,ResumeEntry entry,LanguageCode language,String title,String organization,String location,String summary,java.time.Instant at){initialize(id,at);this.entry=java.util.Objects.requireNonNull(entry,"entry");languageCode=java.util.Objects.requireNonNull(language,"language");update(title,organization,location,summary,at);} public static ResumeEntryTranslation create(UUID id,ResumeEntry entry,LanguageCode language,String title,String organization,String location,String summary,java.time.Instant at){return new ResumeEntryTranslation(id,entry,language,title,organization,location,summary,at);} public void update(String title,String organization,String location,String summary,java.time.Instant at){this.title=requireNonBlank(title,"title");this.organization=requireNonBlank(organization,"organization");this.location=location;this.summary=summary;updatedAt=java.util.Objects.requireNonNull(at,"at");} }
